using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change: discriminator renamed from "Discriminator" to "$type".
            // Keep old name so existing documents are found.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer includes discriminator ("Blog|1" → "1").
            // Keep old composite format so existing documents are found.
            entity.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // removing the shadow "__id" property. Keep old layout so the
            // separate "Id" JSON property in existing documents is still read.
            entity.HasShadowId();
        });

        // Breaking change: HasIndex now throws (Cosmos indexes all properties
        // automatically). Removed the previous HasIndex(b => b.Name) call.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

